using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Http;
using System.IdentityModel.Tokens.Jwt;

public class JwtAuthenticationMiddleware : IMiddleware
{
    private readonly ILogger<JwtAuthenticationMiddleware> _logger;
    private readonly JwtSecurityTokenHandler _tokenHandler;

    public JwtAuthenticationMiddleware(ILogger<JwtAuthenticationMiddleware> logger)
    {
        _logger = logger;
        _tokenHandler = new JwtSecurityTokenHandler();
    }

    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        var tokenString = GetTokenFromAuthorizationHeader(context.Request.Headers);

        if (string.IsNullOrEmpty(tokenString))
        {
            _logger.LogInformation("JWT token not found in request headers");
            return;
        }

        try
        {
            var jwtToken = _tokenHandler.ReadJwtToken(tokenString);

            if (!_tokenHandler.ValidateToken(jwtToken, out SecurityToken securityToken))
            {
                _logger.LogInformation("Invalid JWT token");
                return;
            }

            var jwtSecurityToken = (JwtSecurityToken)securityToken;

            var claims = jwtSecurityToken.Claims;
            foreach (var claim in claims)
            {
                context.User.AddIdentity(new ClaimsIdentity(claims, "JWT"));
            }
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "Failed to process JWT token");
            return;
        }
    }

    private string GetTokenFromAuthorizationHeader(IHeaderDictionary headers)
    {
        if (!headers.ContainsKey("Authorization"))
        {
            return null;
        }

        var authHeader = headers["Authorization"];
        if (string.IsNullOrEmpty(authHeader))
        {
            return null;
        }

        if (!authHeader.StartsWith("Bearer "))
        {
            _logger.LogWarning("Invalid authorization header format");
            return null;
        }

        var token = authHeader.Substring(7);
        if (string.IsNullOrEmpty(token))
        {
            _logger.LogWarning("Empty JWT token found in authorization header");
            return null;
        }

        return token;
    }
